public class AttributeContext extends EvalContext {

    private NodeTest nodeTest;
    private boolean setStarted = false;
    private NodeIterator iterator;
    private NodePointer currentNodePointer;

    /**
     * @param parentContext represents the previous step on the path
     * @param nodeTest is the name of the attribute we are looking for
     */
    public AttributeContext(EvalContext parentContext, NodeTest nodeTest) {
        super(parentContext);
        this.nodeTest = nodeTest;
    }

    public NodePointer getCurrentNodePointer() {
        return currentNodePointer;
    }

    public void reset() {
        setStarted = false;
        iterator = null;
        super.reset();
    }

    public boolean setPosition(int position) {
        if (position < getCurrentPosition()) {
            reset();
        }

        while (getCurrentPosition() < position) {
            if (!nextNode()) {
                return false;
            }
        }
        return true;
    }

    public boolean nextNode() {
        super.setPosition(getCurrentPosition() + 1);
        if (!setStarted) {
            setStarted = true;
            if (nodeTest instanceof NodeNameTest) {
                QName name = ((NodeNameTest) nodeTest).getNodeName();
                iterator =
                    parentContext.getCurrentNodePointer().attributeIterator(name);
            }
            else if (nodeTest instanceof NodeTypeTest) {
                NodeTypeTest test = (NodeTypeTest) nodeTest;
                if (test.getNodeType() == Compiler.NODE_TYPE_NODE) {
                    // For attribute::node(), return all attributes (equivalent to @*)
                    QName name = new QName("*");
                    iterator =
                        parentContext.getCurrentNodePointer().attributeIterator(name);
                }
                else {
                    return false;
                }
            }
            else {
                return false;
            }
        }
        if (iterator == null) {
            return false;
        }
        if (!iterator.setPosition(iterator.getPosition() + 1)) {
            return false;
        }
        currentNodePointer = iterator.getNodePointer();
        return true;
    }
}

